export * from './inplace.component';
export * from './inplace.variants';
export * from './inplace-display.directive';
export * from './inplace-content.directive';
export * from './inplace-closer.directive';
export * from './inplace.imports';

import { Directive, inject } from '@angular/core';

import { HbInplaceComponent } from './inplace.component';

@Directive({
  selector: '[hbInplaceCloser]',
  host: {
    '[attr.data-slot]': "'inplace-closer'",
    '(click)': 'onClick()',
  },
  exportAs: 'hbInplaceCloser',
})
export class HbInplaceCloserDirective {
  private readonly inplace = inject(HbInplaceComponent);

  protected onClick(): void {
    this.inplace.deactivate();
  }
}

import { Directive } from '@angular/core';

@Directive({
  selector: 'ng-template[hbInplaceContent]',
})
export class HbInplaceContentDirective {}

import { Directive } from '@angular/core';

@Directive({
  selector: 'ng-template[hbInplaceDisplay]',
})
export class HbInplaceDisplayDirective {}

import { NgTemplateOutlet } from '@angular/common';
import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  contentChild,
  input,
  model,
  output,
  TemplateRef,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HbInplaceContentDirective } from './inplace-content.directive';
import { HbInplaceDisplayDirective } from './inplace-display.directive';
import { inplaceClass, inplaceContentClass, inplaceDisplayClass } from './inplace.variants';

@Component({
  selector: 'hb-inplace',
  imports: [NgTemplateOutlet],
  template: `
    @if (!hbActive()) {
      <div
        [class]="displayClass"
        data-slot="inplace-display"
        [attr.role]="interactive() ? 'button' : null"
        [attr.tabindex]="interactive() ? 0 : null"
        [attr.data-disabled]="hbDisabled() || null"
        [attr.data-static]="staticDisplay() || null"
        (click)="onDisplayClick()"
        (keydown.enter)="onKey($event)"
        (keydown.space)="onKey($event)"
      >
        @if (displayTpl(); as tpl) {
          <ng-container [ngTemplateOutlet]="tpl" />
        }
      </div>
    } @else {
      <div [class]="contentClass" data-slot="inplace-content">
        @if (contentTpl(); as tpl) {
          <ng-container [ngTemplateOutlet]="tpl" />
        }
      </div>
    }
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'inplace'",
    '[attr.data-active]': 'hbActive() || null',
    '[attr.data-disabled]': 'hbDisabled() || null',
  },
  exportAs: 'hbInplace',
})
export class HbInplaceComponent {
  readonly hbActive = model(false);
  readonly hbDisabled = input(false, { transform: booleanAttribute });
  readonly hbPreventClick = input(false, { transform: booleanAttribute });
  readonly class = input<ClassValue>('');

  readonly hbActivate = output<void>();
  readonly hbDeactivate = output<void>();

  protected readonly displayTpl = contentChild(HbInplaceDisplayDirective, { read: TemplateRef });
  protected readonly contentTpl = contentChild(HbInplaceContentDirective, { read: TemplateRef });

  readonly active = this.hbActive.asReadonly();

  protected readonly displayClass = inplaceDisplayClass;
  protected readonly contentClass = inplaceContentClass;
  protected readonly interactive = computed(() => !this.hbDisabled() && !this.hbPreventClick());
  protected readonly staticDisplay = computed(() => this.hbPreventClick() && !this.hbDisabled());

  protected readonly classes = computed(() => cn(inplaceClass, this.class()));

  activate(): void {
    if (this.hbDisabled() || this.hbActive()) return;
    this.hbActive.set(true);
    this.hbActivate.emit();
  }
  deactivate(): void {
    if (!this.hbActive()) return;
    this.hbActive.set(false);
    this.hbDeactivate.emit();
  }
  toggle(): void {
    this.hbActive() ? this.deactivate() : this.activate();
  }

  protected onDisplayClick(): void {
    if (this.interactive()) this.activate();
  }
  protected onKey(event: Event): void {
    if (!this.interactive()) return;
    event.preventDefault();
    this.activate();
  }
}

import { HbInplaceCloserDirective } from './inplace-closer.directive';
import { HbInplaceContentDirective } from './inplace-content.directive';
import { HbInplaceDisplayDirective } from './inplace-display.directive';
import { HbInplaceComponent } from './inplace.component';

export const HbInplaceImports = [
  HbInplaceComponent,
  HbInplaceDisplayDirective,
  HbInplaceContentDirective,
  HbInplaceCloserDirective,
] as const;

export const inplaceClass = 'inline-flex w-full flex-col text-sm';
export const inplaceDisplayClass =
  'inline-flex w-fit cursor-pointer items-center gap-2 rounded-md px-2 py-1 transition-colors hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring data-[disabled]:pointer-events-none data-[disabled]:cursor-default data-[disabled]:opacity-50 data-[static]:cursor-default data-[static]:hover:bg-transparent';
export const inplaceContentClass = 'w-full';
